import React from 'react';
import {
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Switch,
  FormControlLabel,
  Box,
  Avatar,
  Tooltip,
  Badge,
} from '@mui/material';
import {
  Menu as MenuIcon,
  Brightness4,
  Brightness7,
  Notifications,
  AccountCircle,
  MonitorHeart,
} from '@mui/icons-material';

const Navbar = ({ darkMode, toggleDarkMode, toggleSidebar }) => {
  return (
    <AppBar
      position="fixed"
      sx={{
        zIndex: (theme) => theme.zIndex.drawer + 1,
        background: darkMode
          ? 'linear-gradient(135deg, #0A0A0F 0%, #1A1A2E 50%, #16213E 100%)'
          : 'linear-gradient(135deg, #FFFFFF 0%, #F8FAFC 50%, #E2E8F0 100%)',
        backdropFilter: 'blur(20px)',
        borderBottom: darkMode
          ? '1px solid rgba(139, 92, 246, 0.3)'
          : '1px solid rgba(124, 58, 237, 0.2)',
        boxShadow: darkMode
          ? '0 8px 32px rgba(139, 92, 246, 0.2), 0 0 100px rgba(236, 72, 153, 0.1)'
          : '0 8px 32px rgba(124, 58, 237, 0.15)',
      }}
    >
      <Toolbar sx={{ minHeight: '80px !important' }}>
        <IconButton
          color="inherit"
          aria-label="toggle sidebar"
          onClick={toggleSidebar}
          edge="start"
          sx={{ 
            mr: 3,
            background: darkMode 
              ? 'rgba(139, 92, 246, 0.1)' 
              : 'rgba(124, 58, 237, 0.1)',
            border: darkMode
              ? '1px solid rgba(139, 92, 246, 0.3)'
              : '1px solid rgba(124, 58, 237, 0.2)',
            borderRadius: 2,
            transition: 'all 0.3s ease',
            '&:hover': {
              background: darkMode 
                ? 'rgba(139, 92, 246, 0.2)' 
                : 'rgba(124, 58, 237, 0.2)',
              transform: 'scale(1.05)',
              boxShadow: '0 0 20px rgba(139, 92, 246, 0.4)',
            },
          }}
        >
          <MenuIcon />
        </IconButton>
        
        <Box sx={{ display: 'flex', alignItems: 'center', mr: 2 }}>
          <MonitorHeart 
            sx={{ 
              fontSize: 32, 
              mr: 1,
              background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text',
              filter: 'drop-shadow(0 0 10px rgba(139, 92, 246, 0.5))',
            }} 
          />
          <Typography 
            variant="h6" 
            noWrap 
            component="div" 
            sx={{ 
              flexGrow: 1,
              fontWeight: 800,
              fontSize: '1.5rem',
              background: darkMode
                ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)'
                : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text',
              textShadow: darkMode 
                ? '0 0 30px rgba(139, 92, 246, 0.5)'
                : 'none',
            }}
          >
            SpineSense Pro
          </Typography>
        </Box>

        <Box sx={{ flexGrow: 1 }} />

        <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
          <FormControlLabel
            control={
              <Switch
                checked={darkMode}
                onChange={toggleDarkMode}
                sx={{
                  '& .MuiSwitch-switchBase.Mui-checked': {
                    color: '#8B5CF6',
                    '&:hover': {
                      backgroundColor: 'rgba(139, 92, 246, 0.08)',
                    },
                  },
                  '& .MuiSwitch-switchBase.Mui-checked + .MuiSwitch-track': {
                    background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
                  },
                  '& .MuiSwitch-track': {
                    background: darkMode 
                      ? 'rgba(139, 92, 246, 0.3)'
                      : 'rgba(124, 58, 237, 0.2)',
                  },
                }}
              />
            }
            label={
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                {darkMode ? (
                  <Brightness7 sx={{ color: '#8B5CF6' }} />
                ) : (
                  <Brightness4 sx={{ color: '#7C3AED' }} />
                )}
              </Box>
            }
            labelPlacement="start"
          />
          
          <Tooltip title="Notifications" arrow>
            <IconButton 
              sx={{
                background: darkMode 
                  ? 'rgba(139, 92, 246, 0.1)' 
                  : 'rgba(124, 58, 237, 0.1)',
                border: darkMode
                  ? '1px solid rgba(139, 92, 246, 0.3)'
                  : '1px solid rgba(124, 58, 237, 0.2)',
                borderRadius: 2,
                transition: 'all 0.3s ease',
                '&:hover': {
                  background: darkMode 
                    ? 'rgba(139, 92, 246, 0.2)' 
                    : 'rgba(124, 58, 237, 0.2)',
                  transform: 'scale(1.05)',
                  boxShadow: '0 0 20px rgba(139, 92, 246, 0.4)',
                },
              }}
            >
              <Badge badgeContent={3} color="secondary">
                <Notifications sx={{ color: darkMode ? '#8B5CF6' : '#7C3AED' }} />
              </Badge>
            </IconButton>
          </Tooltip>
          
          <Tooltip title="Profile" arrow>
            <IconButton
              sx={{
                background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
                border: '2px solid rgba(255, 255, 255, 0.2)',
                borderRadius: 2,
                transition: 'all 0.3s ease',
                '&:hover': {
                  transform: 'scale(1.05)',
                  boxShadow: '0 0 30px rgba(139, 92, 246, 0.6)',
                },
              }}
            >
              <Avatar 
                sx={{ 
                  width: 32, 
                  height: 32, 
                  background: 'rgba(255, 255, 255, 0.2)',
                  backdropFilter: 'blur(10px)',
                }}
              >
                <AccountCircle sx={{ color: '#FFFFFF' }} />
              </Avatar>
            </IconButton>
          </Tooltip>
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
